mapper.select:
SELECT punish_id, user_id, type, status, start_time, end_time,
       reason_code, decision_id, operator_id, create_time, update_time
FROM risk_punishment
WHERE decision_id = #{decisionId}
  AND type = #{type}
LIMIT 1

SELECT punish_id, user_id, type, status, start_time, end_time,
       reason_code, decision_id, operator_id, create_time, update_time
FROM risk_punishment
WHERE user_id = #{userId}
  AND status = 'ACTIVE'
  AND start_time <= #{now}
  AND end_time > #{now}
ORDER BY end_time ASC, punish_id ASC

SELECT punish_id, user_id, type, status, start_time, end_time,
       reason_code, decision_id, operator_id, create_time, update_time
FROM risk_punishment
WHERE user_id = #{userId}
ORDER BY create_time DESC, punish_id DESC
LIMIT #{limit} OFFSET #{offset}

SELECT punish_id, user_id, type, status, start_time, end_time,
       reason_code, decision_id, operator_id, create_time, update_time
FROM risk_punishment
WHERE 1=1

    AND user_id = #{userId}


    AND type = #{type}


    AND create_time >= #{beginTime}


    AND create_time <= #{endTime}

ORDER BY create_time DESC, punish_id DESC
LIMIT #{limit} OFFSET #{offset}
